-- eBay reconciliation historical credit-note repair
-- Generated from staging_ebay_module_only_full_repair_plan.csv
-- Scope: only credit notes whose CSV audit traced them to note_private LIKE 'Auto-created via eBay reconciliation%'.
-- Generated rows: 2087 credit notes, excluding already-fixed rows.
-- Behavior:
--   1. Creates Dolibarr available-credit rows for module-created credit notes that do not already have one.
--   2. Applies credit to the source invoice up to the live invoice total only; any excess remains available credit.
--   3. Resolves source-missing one-invoice rows by invoice ref at runtime.
--   4. Reduces payment allocations by the applied credit amount, then recomputes payment header totals from payment lines.
--   5. Marks repaired credit notes as paid/closed after they become available credit.
-- Safety:
--   The DML filters out credit notes that already have llx_societe_remise_except rows, so re-running is idempotent for repaired notes.

SET @ebay_repair_user_id := 11;
SET @ebay_repair_started_at := NOW();
SET @ebay_repair_tag := CONCAT('ebay_credit_repair_', DATE_FORMAT(@ebay_repair_started_at, '%Y%m%d_%H%i%s'));

CREATE TEMPORARY TABLE tmp_ebay_credit_repair_input (
  credit_id INT PRIMARY KEY,
  credit_ref VARCHAR(30),
  order_ref VARCHAR(255),
  source_invoice_id INT NULL,
  source_invoice_ref VARCHAR(30),
  credit_amount DECIMAL(24,8) NOT NULL,
  planned_apply_amount DECIMAL(24,8) NOT NULL,
  payment_id INT NULL,
  repair_action VARCHAR(100)
) ENGINE=Memory;


CREATE TEMPORARY TABLE tmp_ebay_one_payment_per_invoice AS
SELECT fk_facture, MAX(fk_paiement) AS payment_id, COUNT(*) AS payment_line_count
FROM llx_paiement_facture
GROUP BY fk_facture
HAVING COUNT(*) = 1;

CREATE TEMPORARY TABLE tmp_ebay_credit_repair_raw_todo AS
SELECT
  i.credit_id,
  i.credit_ref,
  i.order_ref,
  COALESCE(i.source_invoice_id, inv_by_ref.rowid) AS source_invoice_id,
  COALESCE(NULLIF(i.source_invoice_ref, ''), inv_by_ref.ref) AS source_invoice_ref,
  i.credit_amount,
  i.planned_apply_amount,
  GREATEST(0, COALESCE(src.total_ttc, inv_by_ref.total_ttc, 0)) AS live_invoice_total,
  COALESCE(i.payment_id, pay.payment_id) AS payment_id,
  i.repair_action
FROM tmp_ebay_credit_repair_input i
JOIN llx_facture cn ON cn.rowid = i.credit_id
LEFT JOIN llx_facture inv_by_ref ON i.source_invoice_id IS NULL AND i.source_invoice_ref <> '' AND inv_by_ref.ref = i.source_invoice_ref
LEFT JOIN llx_facture src ON src.rowid = i.source_invoice_id
LEFT JOIN tmp_ebay_one_payment_per_invoice pay ON pay.fk_facture = COALESCE(i.source_invoice_id, inv_by_ref.rowid)
WHERE cn.note_private LIKE 'Auto-created via eBay reconciliation%'
  AND NOT EXISTS (
    SELECT 1 FROM llx_societe_remise_except sre WHERE sre.fk_facture_source = i.credit_id
  );

CREATE TEMPORARY TABLE tmp_ebay_credit_repair_todo AS
SELECT
  x.credit_id,
  x.credit_ref,
  x.order_ref,
  x.source_invoice_id,
  x.source_invoice_ref,
  x.credit_amount,
  CASE
    WHEN x.source_invoice_id IS NULL THEN 0
    ELSE ROUND(GREATEST(0, LEAST(x.planned_apply_amount, x.live_invoice_total - x.apply_before_this_row)), 8)
  END AS apply_amount,
  x.payment_id,
  x.repair_action
FROM (
  SELECT r.*,
    COALESCE(SUM(r.planned_apply_amount) OVER (
      PARTITION BY r.source_invoice_id
      ORDER BY r.credit_id
      ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING
    ), 0) AS apply_before_this_row
  FROM tmp_ebay_credit_repair_raw_todo r
) x;

CREATE TEMPORARY TABLE tmp_ebay_credit_repair_invoice_apply AS
SELECT source_invoice_id, payment_id, ROUND(SUM(apply_amount), 8) AS apply_total
FROM tmp_ebay_credit_repair_todo
WHERE source_invoice_id IS NOT NULL AND apply_amount > 0
GROUP BY source_invoice_id, payment_id;

SELECT 'PRECHECK_TODO_CREDIT_NOTES' AS metric, COUNT(*) AS value FROM tmp_ebay_credit_repair_todo;
SELECT 'PRECHECK_APPLY_TO_INVOICE_TOTAL' AS metric, ROUND(SUM(apply_amount), 2) AS value FROM tmp_ebay_credit_repair_todo;
SELECT 'PRECHECK_AVAILABLE_CREDIT_TOTAL' AS metric, ROUND(SUM(credit_amount), 2) AS value FROM tmp_ebay_credit_repair_todo;
SELECT repair_action, COUNT(*) rows_count, ROUND(SUM(credit_amount), 2) credit_total, ROUND(SUM(apply_amount), 2) apply_total
FROM tmp_ebay_credit_repair_todo
GROUP BY repair_action
ORDER BY repair_action;
SELECT 'PRECHECK_UNRESOLVED_SOURCE_ROWS' AS metric, COUNT(*) AS value
FROM tmp_ebay_credit_repair_todo
WHERE source_invoice_id IS NULL AND repair_action NOT IN ('MARK_CN_AVAILABLE_STANDALONE_NO_SOURCE_INVOICE','REVIEW_MISSING_SOURCE_MULTIPLE_INVOICES');

START TRANSACTION;

  entity, fk_soc, discount_type, datec, amount_ht, amount_tva, amount_ttc, tva_tx, vat_src_code,
  fk_user, fk_facture_line, fk_facture, fk_facture_source, description,
  multicurrency_code, multicurrency_tx, multicurrency_amount_ht, multicurrency_amount_tva, multicurrency_amount_ttc
)
SELECT
  cn.entity, cn.fk_soc, 0, NOW(), ABS(t.credit_amount), 0, ABS(t.credit_amount), 0, '',
  @ebay_repair_user_id, NULL, NULL, cn.rowid, '(CREDIT_NOTE)',
  cn.multicurrency_code, cn.multicurrency_tx, ABS(t.credit_amount), 0, ABS(t.credit_amount)
FROM tmp_ebay_credit_repair_todo t
JOIN llx_facture cn ON cn.rowid = t.credit_id;

  fk_facture, fk_parent_line, fk_product, label, description, vat_src_code, tva_tx,
  localtax1_tx, localtax1_type, localtax2_tx, localtax2_type,
  qty, remise_percent, remise, fk_remise_except, subprice, subprice_ttc, price,
  total_ht, total_tva, total_localtax1, total_localtax2, total_ttc,
  product_type, date_start, date_end, info_bits, buy_price_ht,
  fk_product_fournisseur_price, batch, fk_warehouse, special_code, rang,
  fk_contract_line, fk_unit, import_key, fk_code_ventilation, situation_percent,
  fk_prev_id, fk_user_author, fk_user_modif, fk_multicurrency,
  multicurrency_code, multicurrency_subprice, multicurrency_subprice_ttc,
  multicurrency_total_ht, multicurrency_total_tva, multicurrency_total_ttc,
  ref_ext, extraparams
)
SELECT
  t.source_invoice_id, NULL, NULL, NULL, '(CREDIT_NOTE)', '', 0,
  0, '0', 0, '0',
  1, 0, 0, sre.rowid, -ABS(t.apply_amount), 0, NULL,
  -ABS(t.apply_amount), 0, 0, 0, -ABS(t.apply_amount),
  0, NULL, NULL, 2, 0,
  NULL, '', 0, 0, -1,
  NULL, NULL, NULL, 0, 100,
  NULL, @ebay_repair_user_id, @ebay_repair_user_id, 0,
  '', -ABS(t.apply_amount), 0,
  -ABS(t.apply_amount), 0, -ABS(t.apply_amount),
  '', NULL
FROM tmp_ebay_credit_repair_todo t
JOIN llx_societe_remise_except sre ON sre.fk_facture_source = t.credit_id
WHERE t.source_invoice_id IS NOT NULL AND t.apply_amount > 0;

UPDATE llx_societe_remise_except sre
JOIN llx_facturedet fd ON fd.fk_remise_except = sre.rowid
JOIN tmp_ebay_credit_repair_todo t ON t.credit_id = sre.fk_facture_source
SET sre.fk_facture_line = fd.rowid
WHERE t.apply_amount > 0;

UPDATE llx_facture f
JOIN tmp_ebay_credit_repair_invoice_apply a ON a.source_invoice_id = f.rowid
SET f.total_ht = ROUND(f.total_ht - a.apply_total, 8),
    f.total_ttc = ROUND(f.total_ttc - a.apply_total, 8),
    f.multicurrency_total_ht = ROUND(f.multicurrency_total_ht - a.apply_total, 8),
    f.multicurrency_total_ttc = ROUND(f.multicurrency_total_ttc - a.apply_total, 8),
    f.tms = NOW();

UPDATE llx_paiement_facture pf
JOIN tmp_ebay_credit_repair_invoice_apply a ON a.payment_id = pf.fk_paiement AND a.source_invoice_id = pf.fk_facture
SET pf.amount = ROUND(GREATEST(0, pf.amount - a.apply_total), 8),
    pf.multicurrency_amount = ROUND(GREATEST(0, pf.multicurrency_amount - a.apply_total), 8)
WHERE a.payment_id IS NOT NULL;

UPDATE llx_paiement p
JOIN (
  SELECT fk_paiement, ROUND(SUM(amount), 8) AS new_amount, ROUND(SUM(multicurrency_amount), 8) AS new_multicurrency_amount
  FROM llx_paiement_facture
  WHERE fk_paiement IN (SELECT payment_id FROM tmp_ebay_credit_repair_invoice_apply WHERE payment_id IS NOT NULL)
  GROUP BY fk_paiement
) s ON s.fk_paiement = p.rowid
SET p.amount = s.new_amount,
    p.multicurrency_amount = s.new_multicurrency_amount,
    p.tms = NOW();

UPDATE llx_facture cn
JOIN tmp_ebay_credit_repair_todo t ON t.credit_id = cn.rowid
SET cn.paye = 1,
    cn.fk_statut = 2,
    cn.note_private = CONCAT(COALESCE(cn.note_private, ''), '
Historical eBay credit repair: made available/applied on ', DATE_FORMAT(@ebay_repair_started_at, '%Y-%m-%d %H:%i:%s'), '.')
WHERE cn.type = 2;

SELECT 'VERIFY_REMISE_ROWS_CREATED' AS metric, COUNT(*) AS value
FROM llx_societe_remise_except sre
JOIN tmp_ebay_credit_repair_todo t ON t.credit_id = sre.fk_facture_source;
SELECT 'VERIFY_APPLIED_LINES_CREATED' AS metric, COUNT(*) AS value
FROM llx_facturedet fd
JOIN llx_societe_remise_except sre ON sre.rowid = fd.fk_remise_except
JOIN tmp_ebay_credit_repair_todo t ON t.credit_id = sre.fk_facture_source
WHERE t.apply_amount > 0;
SELECT 'VERIFY_NEGATIVE_SOURCE_INVOICES' AS metric, COUNT(*) AS value
FROM llx_facture f
JOIN tmp_ebay_credit_repair_invoice_apply a ON a.source_invoice_id = f.rowid
WHERE f.total_ttc < -0.00001;
SELECT 'VERIFY_NEGATIVE_PAYMENT_LINES' AS metric, COUNT(*) AS value
FROM llx_paiement_facture pf
JOIN tmp_ebay_credit_repair_invoice_apply a ON a.payment_id = pf.fk_paiement AND a.source_invoice_id = pf.fk_facture
WHERE pf.amount < -0.00001;
SELECT 'VERIFY_PAYMENT_HEADER_MISMATCHES' AS metric, COUNT(*) AS value
FROM llx_paiement p
JOIN (SELECT fk_paiement, ROUND(SUM(amount), 8) AS line_sum FROM llx_paiement_facture GROUP BY fk_paiement) s ON s.fk_paiement = p.rowid
WHERE p.rowid IN (SELECT payment_id FROM tmp_ebay_credit_repair_invoice_apply WHERE payment_id IS NOT NULL)
  AND ABS(p.amount - s.line_sum) > 0.00001;
SELECT 'VERIFY_UNRESOLVED_SOURCE_ROWS' AS metric, COUNT(*) AS value
FROM tmp_ebay_credit_repair_todo
WHERE source_invoice_id IS NULL AND repair_action NOT IN ('MARK_CN_AVAILABLE_STANDALONE_NO_SOURCE_INVOICE','REVIEW_MISSING_SOURCE_MULTIPLE_INVOICES');

SELECT t.credit_ref, t.source_invoice_ref, t.credit_amount, t.apply_amount, f.total_ttc AS invoice_total_after, pf.amount AS payment_line_after
FROM tmp_ebay_credit_repair_todo t
LEFT JOIN llx_facture f ON f.rowid = t.source_invoice_id
LEFT JOIN llx_paiement_facture pf ON pf.fk_paiement = t.payment_id AND pf.fk_facture = t.source_invoice_id
ORDER BY t.credit_id
LIMIT 20;

ROLLBACK;
SELECT 'DRY_RUN_ROLLED_BACK_NO_DATA_CHANGED' AS metric, 1 AS value;
